/* Optimized Lazy Loading - Without Console Spam */
function preloadCriticalResources(){[{href:"/css/landing.min.css",as:"style"},{href:"/js/landing.min.js",as:"script"}].forEach(e=>{if(!document.querySelector(`link[href="${e.href}"]`)){const r=document.createElement("link");r.rel="preload",r.href=e.href,r.as=e.as,document.head.appendChild(r)}})}
document.addEventListener("DOMContentLoaded",()=>{
const imgObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;if(img.dataset.src){img.src=img.dataset.src;img.removeAttribute('data-src')}if(img.dataset.srcset){img.srcset=img.dataset.srcset;img.removeAttribute('data-srcset')}img.classList.add("loaded");observer.unobserve(img)}})},{rootMargin:"50px 0px",threshold:0.01});
document.querySelectorAll("img[data-src]").forEach(img=>imgObserver.observe(img));
const bgObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){const el=entry.target;const bg=el.dataset.bg;if(bg){el.style.backgroundImage=`url(${bg})`;el.classList.add("bg-loaded");el.removeAttribute('data-bg')}observer.unobserve(el)}})},{rootMargin:"100px 0px"});
document.querySelectorAll("[data-bg]").forEach(el=>bgObserver.observe(el));
if("requestIdleCallback"in window){requestIdleCallback(()=>preloadCriticalResources())}else{setTimeout(preloadCriticalResources,100)}
});